--
-- Table structure for table `daily_meal_plan`
--

DROP TABLE IF EXISTS `daily_meal_plan`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `daily_meal_plan` (
  `id` int NOT NULL AUTO_INCREMENT,
  `weekly_plan_id` int NOT NULL,
  `plan_date` date NOT NULL,
  `meal_type` varchar(20) NOT NULL,
  `recipe_id` varchar(50) NOT NULL,
  `recipe_name` varchar(255) NOT NULL,
  `servings` decimal(10,2) NOT NULL,
  `target_cal` decimal(10,2) NOT NULL,
  `target_fat` decimal(10,2) NOT NULL,
  `target_carbs` decimal(10,2) NOT NULL,
  `target_protein` decimal(10,2) NOT NULL,
  `target_fiber` decimal(10,2) DEFAULT NULL,
  `target_sugar` decimal(10,2) DEFAULT NULL,
  `target_sodium` decimal(10,2) DEFAULT NULL,
  `status` varchar(20) DEFAULT 'pending',
  `updated_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `weekly_plan_id` (`weekly_plan_id`,`plan_date`,`meal_type`),
  KEY `idx_daily_meal_plan_weekly` (`weekly_plan_id`),
  KEY `idx_daily_meal_plan_date` (`plan_date`),
  CONSTRAINT `daily_meal_plan_ibfk_1` FOREIGN KEY (`weekly_plan_id`) REFERENCES `weekly_diet_plan` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=1424 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
