DROP TABLE IF EXISTS `matrices`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `matrices` (
  `id` int NOT NULL AUTO_INCREMENT,
  `user_id` varchar(10) NOT NULL,
  `bmi` float NOT NULL,
  `bmi_category` varchar(20) NOT NULL,
  `rmr` float NOT NULL,
  `tdee` float NOT NULL,
  `total_calories` float NOT NULL,
  `macronutrient_split` json DEFAULT NULL,
  `macronutrient_grams` json DEFAULT NULL,
  `meal_distribution` json DEFAULT NULL,
  `meal_calories` json DEFAULT NULL,
  `diet_labels` json DEFAULT NULL,
  `health_labels` json DEFAULT NULL,
  `exercise_adjustment` decimal(10,2) DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `matrices_ibfk_1` (`user_id`),
  CONSTRAINT `matrices_ibfk_1` FOREIGN KEY (`user_id`) REFERENCES `users` (`id`) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=100 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
