--
-- Table structure for table `users`
--

DROP TABLE IF EXISTS `users`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `users` (
  `id` varchar(10) NOT NULL,
  `account_id` int NOT NULL,
  `name` varchar(255) NOT NULL,
  `age` int DEFAULT NULL,
  `gender` enum('male','female') NOT NULL,
  `weight` decimal(5,2) DEFAULT NULL,
  `height` decimal(5,2) DEFAULT NULL,
  `activity_level` enum('sedentary','light','moderate','active','very active') NOT NULL,
  `goal` enum('gain','maintain','loss') NOT NULL,
  `diseases` json DEFAULT NULL,
  `allergies` json DEFAULT NULL,
  `meal_types` json DEFAULT NULL,
  `exercise_recommendation` enum('yes','no') NOT NULL,
